	@Test
	void possibleOnlyExtensionGapIsClosedWhileLegacyRegistryRemainsForOtherParityGates() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		DeterministicStatistics statistics = new DeterministicStatistics();
		MapBindingSet possibleSeed = new MapBindingSet(1);
		possibleSeed.addBinding("seed", resource("possible-seed"));
		BindingSetAssignment maybeSeed = new BindingSetAssignment();
		maybeSeed.setBindingNames(Set.of("seed"));
		maybeSeed.setBindingSets(List.of(possibleSeed, new MapBindingSet()));
		Extension unresolvedExtension = new Extension(pattern("entity", B, "value"),
				new ExtensionElem(new Str(new Var("seed")), "derived"));
		TupleExpr legacyOwned = new Join(maybeSeed, unresolvedExtension);
		TupleExpr pureInner = new Join(pattern("entity", A, "shared"), pattern("shared", C, "value"));
		RuleRegistry registry = LmdbCascadesRuleProvider.rules(statistics);
		List<String> registeredRuleIds = registry.rules().stream().map(CascadesRule::id).toList();

		assertTrue(registeredRuleIds.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
				() -> "The production registry must retain the canonical-gap compatibility owner: "
						+ registeredRuleIds);

		Extraction extraction = extract(legacyOwned, statistics);
		MemoJoinRegionExtractor.Result result = extraction.result();
		List<String> legacyGapRules = applicableRuleIds(registry, legacyOwned, statistics);
		List<String> pureInnerRules = applicableRuleIds(registry, pureInner, statistics);
		assertAll(
				() -> assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(legacyOwned),
						"The legacy route must also reject order-dependent possible-only scalar input"),
				() -> assertTrue(LmdbCascadesConnectedJoinPlanner
						.plan(legacyOwned.clone(), Set.of(), statistics, statistics)
						.isEmpty()),
				() -> assertEquals(MemoJoinRegionExtractor.Status.UNSUPPORTED_SEMANTIC_BARRIER, result.status()),
				() -> assertFalse(result.supported()),
				() -> assertFalse(legacyGapRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						legacyGapRules::toString),
				() -> assertFalse(pureInnerRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						pureInnerRules::toString),
				() -> assertTrue(result.boundaries()
						.stream()
						.anyMatch(boundary -> boundary
								.reason() == MemoJoinRegionExtractor.BoundaryReason.NON_JOIN_COMPOSITE
								&& "Extension".equals(boundary.operator())
								&& boundary.detail().contains("possible but not assured sibling producer")
								&& boundary.detail().contains("seed")),
						result.boundaries()::toString));
	}

	@Test
	void alternativeAssuredExtensionSuppliersUseScopedRouteAndPreserveErrorRows() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		DeterministicStatistics statistics = new DeterministicStatistics();
		StatementPattern firstSupplier = pattern("firstRow", A, "seed");
		StatementPattern secondSupplier = pattern("secondRow", B, "seed");
		Extension extension = new Extension(pattern("extensionRow", C, "value"),
				new ExtensionElem(new Str(new Var("seed")), "derived"));
		TupleExpr input = join(firstSupplier, secondSupplier, extension);
		Resource goodSeed = resource("extension-good-seed");
		Value errorSeed = VF.createBNode("extension-error-seed");
		Statement duplicateFirstGood = statement(resource("first-good"), A, goodSeed);
		Statement duplicateSecondError = statement(resource("second-error"), B, errorSeed);
		ListTripleSource tripleSource = new ListTripleSource(List.of(
				duplicateFirstGood,
				duplicateFirstGood,
				statement(resource("first-error"), A, errorSeed),
				statement(resource("second-good"), B, goodSeed),
				duplicateSecondError,
				duplicateSecondError,
				statement(resource("extension-row"), C, resource("extension-value"))));
		Map<String, Long> expectedBag = evaluateBag(input, tripleSource);
		TupleExpr planningInput = input.clone();
		Extraction extraction = extract(input, statistics);

		CascadesPlan scoped = new LmdbCascadesOptimizer(statistics, false)
				.planPreparedInput(planningInput, autoGoal(planningInput));
		TupleExpr selected = scoped.tupleExpr().orElseThrow();
		List<String> applicableRules = applicableRuleIds(LmdbCascadesRuleProvider.rules(statistics), input, statistics);
		var dependency = extraction.result().region().dependencies().getFirst();

		assertAll(
				() -> assertEquals(2, expectedBag.size(), "Both successful and scalar-error rows must survive"),
				() -> assertTrue(expectedBag.values().stream().allMatch(multiplicity -> multiplicity == 2L),
						"Each producer alternative must retain duplicate multiplicity"),
				() -> assertTrue(expectedBag.keySet().stream().anyMatch(row -> row.contains("derived="))),
				() -> assertTrue(expectedBag.keySet().stream().anyMatch(row -> row.contains("derived=null")),
						"STR over a blank node must preserve the row with the target unbound"),
				() -> assertTrue(extraction.result().supported(), extraction.result().boundaries()::toString),
				() -> assertEquals(1, dependency.producerClauses().size()),
				() -> assertEquals(2, dependency.producerClauses().getFirst().alternatives().size(),
						"Either assured sibling may satisfy the exact producer clause"),
				() -> assertTrue(dependency.producerClauses()
						.getFirst()
						.alternatives()
						.stream()
						.allMatch(state -> state.producers().size() == 1)),
				() -> assertEquals(OptimizationCompleteness.COMPLETE, scoped.completeness(),
						scoped.diagnostics()::toString),
				() -> assertTrue(scoped.pendingTasks().isEmpty(), scoped.pendingTasks()::toString),
				() -> assertTrue(hasScopedJoinProof(scoped)),
				() -> assertFalse(applicableRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						applicableRules::toString),
				() -> assertEquals(expectedBag, evaluateBag(planningInput, tripleSource),
						"Planning must not mutate the Extension-bearing input"),
				() -> assertEquals(expectedBag, evaluateBag(selected, tripleSource), selected::toString));
	}

	@Test
	void externalOnlyExtensionInputUsesScopedRouteWhenUnboundOrBound() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		DeterministicStatistics statistics = new DeterministicStatistics();
		Extension extension = new Extension(pattern("entity", A, "value"),
				new ExtensionElem(new Str(new Var("tenant")), "derived"));
		TupleExpr input = new Join(extension, pattern("value", C, "tail"));
		Statement duplicateBase = statement(resource("external-entity"), A, resource("external-value"));
		Statement duplicateTail = statement(resource("external-value"), C, resource("external-tail"));
		ListTripleSource tripleSource = new ListTripleSource(List.of(
				duplicateBase, duplicateBase, duplicateTail, duplicateTail));
		MapBindingSet boundTenant = new MapBindingSet(1);
		boundTenant.addBinding("tenant", resource("external-tenant"));
		Map<String, Long> expectedUnbound = evaluateBag(input, tripleSource);
		Map<String, Long> expectedBound = evaluateBag(input, tripleSource, boundTenant);
		Extraction extraction = extract(input, statistics);

		TupleExpr unboundInput = input.clone();
		CascadesPlan unbound = new LmdbCascadesOptimizer(statistics, false)
				.planPreparedInput(unboundInput, autoGoal(unboundInput));
		TupleExpr boundInput = input.clone();
		CascadesPlan bound = new LmdbCascadesOptimizer(statistics, false)
				.planPreparedInput(boundInput, autoGoal(boundInput, boundTenant));
		List<String> applicableRules = applicableRuleIds(LmdbCascadesRuleProvider.rules(statistics), input, statistics);

		assertAll(
				() -> assertEquals(4L, resultBagSize(expectedUnbound)),
				() -> assertTrue(expectedUnbound.keySet().stream().allMatch(row -> row.contains("derived=null")),
						expectedUnbound::toString),
				() -> assertEquals(4L, resultBagSize(expectedBound)),
				() -> assertTrue(expectedBound.keySet()
						.stream()
						.allMatch(row -> row.contains("derived=") && !row.contains("derived=null")),
						expectedBound::toString),
				() -> assertTrue(extraction.result().supported(), extraction.result().boundaries()::toString),
				() -> assertTrue(extraction.result().region().dependencies().isEmpty(),
						"No sibling can produce the external-only input"),
				() -> assertEquals(OptimizationCompleteness.COMPLETE, unbound.completeness(),
						unbound.diagnostics()::toString),
				() -> assertEquals(OptimizationCompleteness.COMPLETE, bound.completeness(),
						bound.diagnostics()::toString),
				() -> assertTrue(hasScopedJoinProof(unbound), unbound.memo()::toString),
				() -> assertTrue(hasScopedJoinProof(bound), bound.memo()::toString),
				() -> assertFalse(applicableRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						applicableRules::toString),
				() -> assertEquals(expectedUnbound,
						evaluateBag(unbound.tupleExpr().orElseThrow(), tripleSource)),
				() -> assertEquals(expectedBound,
						evaluateBag(bound.tupleExpr().orElseThrow(), tripleSource, boundTenant)));
	}

	@Test
	void safeNonScopeChangingUnionAtomicFactorUsesScopedRouteAndPreservesDuplicateBag() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		DeterministicStatistics statistics = new DeterministicStatistics();
		StatementPattern firstBranch = new StatementPattern(new Var("entity"),
				Var.of("unionA", A, false, true), new Var("shared"));
		StatementPattern secondBranch = new StatementPattern(new Var("entity"),
				Var.of("unionB", B, false, true), new Var("shared"));
		StatementPattern joinedValue = new StatementPattern(new Var("shared"),
				Var.of("unionC", C, false, true), new Var("value"));
		Union union = new Union(firstBranch, secondBranch);
		union.setVariableScopeChange(false);
		TupleExpr input = new Join(union, joinedValue);
		Resource entity = resource("union-entity");
		Resource shared = resource("union-shared");
		Resource value = resource("union-value");
		List<Statement> statements = List.of(
				statement(entity, A, shared),
				statement(entity, B, shared),
				statement(shared, C, value));
		ListTripleSource tripleSource = new ListTripleSource(statements);
		Map<String, Long> expectedBag = evaluateBag(input, tripleSource);
		TupleExpr planningInput = input.clone();

		CascadesPlan scoped = new LmdbCascadesOptimizer(statistics, false)
				.planPreparedInput(planningInput, autoGoal(planningInput));
		TupleExpr selected = scoped.tupleExpr().orElseThrow();
		RuleRegistry registry = LmdbCascadesRuleProvider.rules(statistics);
		List<String> applicableRules = applicableRuleIds(registry, input, statistics);
		List<String> unionApplicableRules = applicableRuleIds(registry, union, statistics);
		Join selectedOuterJoin = assertInstanceOf(Join.class, selected);
		List<TupleExpr> directChildren = List.of(selectedOuterJoin.getLeftArg(), selectedOuterJoin.getRightArg());
		List<Projection> directChildProjections = directChildren
				.stream()
				.filter(Projection.class::isInstance)
				.map(Projection.class::cast)
				.toList();
		long directUnionCount = directChildren.stream().filter(Union.class::isInstance).count();
		boolean originalUnionWinner = directUnionCount == 1L && directChildProjections.isEmpty();
		boolean factoredProjectionWinner = directUnionCount == 0L && directChildProjections.size() == 1;
		Projection finiteDomainProjection = factoredProjectionWinner ? directChildProjections.getFirst() : null;
		MemoInput selectedRightInput = factoredProjectionWinner
				? scoped.winner()
						.orElseThrow()
						.expression()
						.executableInputs()
						.stream()
						.filter(inputSlot -> inputSlot.role() == MemoInput.Role.RIGHT)
						.findFirst()
						.orElseThrow()
				: null;

		assertAll(
				() -> assertTrue(expectedBag.values().stream().anyMatch(multiplicity -> multiplicity > 1L),
						"The fixture must exercise duplicate UNION bag rows"),
				() -> assertEquals(OptimizationCompleteness.COMPLETE, scoped.completeness(),
						scoped.diagnostics()::toString),
				() -> assertTrue(scoped.pendingTasks().isEmpty(), scoped.pendingTasks()::toString),
				() -> assertTrue(hasScopedJoinProof(scoped),
						"The scoped join route must export the UNION-bearing derivation"),
				() -> assertFalse(applicableRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						applicableRules::toString),
				() -> assertTrue(unionApplicableRules.contains("lmdb-union-constants-to-values"),
						"The specialized finite VALUES alternative must remain registered and applicable: "
								+ unionApplicableRules),
				() -> assertEquals(expectedBag, evaluateBag(planningInput, tripleSource),
						"Cascades planning must not mutate the UNION-bearing input"),
				() -> assertEquals(expectedBag, evaluateBag(selected, tripleSource), selected::toString),
				() -> assertTrue(originalUnionWinner || factoredProjectionWinner,
						"Canonical costing may select either the original UNION or its rule-16 projected relation: "
								+ selected),
				() -> {
					if (factoredProjectionWinner) {
						assertAll(
								() -> assertTrue(finiteDomainProjection.getArg() instanceof Join,
										"Rule 16's finite VALUES rewrite must remain a transparent projected relation"),
								() -> assertEquals("hash",
										selectedOuterJoin.getStringMetricPlanned("optimizer.joinAlgorithmHint"),
										"A selected outer join containing a Projection must use the isolated hash route"),
								() -> assertEquals(PhysicalProperties.InputConsumption.ANY,
										selectedRightInput.requiredProperties().inputConsumption(),
										"The hash Join's RIGHT contract must not request selected-prefix execution"));
					}
				});
	}

	@Test
	void safeNonScopeChangingLeftJoinAtomicFactorUsesScopedRouteAndPreservesDuplicateUnboundBag() {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "true");
		DeterministicStatistics statistics = new DeterministicStatistics();
		StatementPattern requiredRows = new StatementPattern(new Var("person"),
				Var.of("optionalA", A, false, true), new Var("x"));
		StatementPattern optionalRows = new StatementPattern(new Var("person"),
				Var.of("optionalB", B, false, true), new Var("nick"));
		StatementPattern names = new StatementPattern(new Var("x"),
				Var.of("optionalC", C, false, true), new Var("name"));
		LeftJoin optional = new LeftJoin(requiredRows, optionalRows);
		optional.setVariableScopeChange(false);
		TupleExpr input = new Join(optional, names);
		Resource firstPerson = resource("optional-person1");
		Resource secondPerson = resource("optional-person2");
		Resource firstX = resource("optional-x1");
		Resource secondX = resource("optional-x2");
		Resource nick = resource("optional-nick");
		Statement duplicateOptionalRow = statement(firstPerson, B, nick);
		ListTripleSource tripleSource = new ListTripleSource(List.of(
				statement(firstPerson, A, firstX),
				statement(secondPerson, A, secondX),
				duplicateOptionalRow,
				duplicateOptionalRow,
				statement(firstX, C, resource("optional-name1")),
				statement(secondX, C, resource("optional-name2"))));
		Map<String, Long> expectedBag = evaluateBag(input, tripleSource);
		TupleExpr planningInput = input.clone();

		CascadesPlan scoped = new LmdbCascadesOptimizer(statistics, false)
				.planPreparedInput(planningInput, autoGoal(planningInput));
		TupleExpr selected = scoped.tupleExpr().orElseThrow();
		List<String> applicableRules = applicableRuleIds(LmdbCascadesRuleProvider.rules(statistics), input, statistics);
		long selectedOptionalFactors = factorBag(selected).entrySet()
				.stream()
				.filter(entry -> entry.getKey().startsWith("LeftJoin:"))
				.mapToLong(Map.Entry::getValue)
				.sum();
		TupleExpr selectedFirst = leftmostFactor(selected);

		assertAll(
				() -> assertTrue(expectedBag.values().stream().anyMatch(multiplicity -> multiplicity > 1L),
						"The fixture must exercise duplicate OPTIONAL bag rows"),
				() -> assertTrue(expectedBag.keySet().stream().anyMatch(row -> !row.contains("nick=")),
						"The fixture must retain an unmatched row with ?nick unbound"),
				() -> assertEquals(OptimizationCompleteness.COMPLETE, scoped.completeness(),
						scoped.diagnostics()::toString),
				() -> assertTrue(scoped.pendingTasks().isEmpty(), scoped.pendingTasks()::toString),
				() -> assertTrue(hasScopedJoinProof(scoped),
						"The scoped join route must export the OPTIONAL-bearing derivation"),
				() -> assertFalse(applicableRules.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						applicableRules::toString),
				() -> assertEquals(expectedBag, evaluateBag(planningInput, tripleSource),
						"Cascades planning must not mutate the OPTIONAL-bearing input"),
				() -> assertEquals(expectedBag, evaluateBag(selected, tripleSource), selected::toString),
				() -> assertEquals(1L, selectedOptionalFactors,
						"The selected outer join plan must retain exactly one atomic OPTIONAL factor"),
				() -> assertTrue(selectedFirst instanceof StatementPattern,
						() -> "The selective sibling must precede the OPTIONAL factor: " + selected),
				() -> assertEquals(C, selectedFirst instanceof StatementPattern pattern
						? pattern.getPredicateVar().getValue()
						: null,
						() -> "The selective sibling must precede the OPTIONAL factor: " + selected));
	}

